-- Borrado de tablas en orden inverso (por dependencias)
DROP TABLE IF EXISTS "PARTIDOS_JUDICIALES";
DROP TABLE IF EXISTS "SEDES";
DROP TABLE IF EXISTS "MUNICIPIOS";
DROP TABLE IF EXISTS "PROVINCIAS";
DROP TABLE IF EXISTS "TIPOS_JUZGADOS";
DROP TABLE IF EXISTS "CCAA";

-- Tabla CCAA
CREATE TABLE IF NOT EXISTS "CCAA" (
	"idCCAA"	INTEGER NOT NULL,
	"Nombre"	TEXT NOT NULL,
	PRIMARY KEY("idCCAA")
);
-- Tabla TIPOS_JUZGADOS
CREATE TABLE IF NOT EXISTS "TIPOS_JUZGADOS" (
	"id"	INTEGER,
	"tipo"	TEXT NOT NULL,
	PRIMARY KEY("id" AUTOINCREMENT)
	);
-- Tabla PROVINCIAS
CREATE TABLE IF NOT EXISTS "PROVINCIAS" (
    "idProvincia" INTEGER NOT NULL,
    "idCCAA" INTEGER NOT NULL,
    "Provincia" TEXT,
    PRIMARY KEY ("idProvincia"),
    FOREIGN KEY ("idCCAA") REFERENCES "CCAA" ("idCCAA")
);
-- Tabla MUNICIPIOS
CREATE TABLE IF NOT EXISTS "MUNICIPIOS" (
	"idMunicipio"	INTEGER,
	"idProvincia"	INTEGER NOT NULL,
	"codMunicipio"	INTEGER NOT NULL,
	"DC"	INTEGER NOT NULL,
	"Municipio"	TEXT NOT NULL,
	PRIMARY KEY("idMunicipio" AUTOINCREMENT)
);
-- Tabla SEDES
CREATE TABLE IF NOT EXISTS "SEDES" (
	"id_juzgado"	INTEGER,
	"municipio"	TEXT,
	"nombre"	TEXT,
	"direccion"	TEXT,
	"telefono"	TEXT,
	"codigo_postal"	TEXT,
	PRIMARY KEY("id_juzgado" AUTOINCREMENT)
);

CREATE TABLE IF NOT EXISTS "PARTIDOS_JUDICIALES" (
	"id"	INTEGER,
	"provincia"	TEXT,
	"id_juzgado"	INTEGER,
	"municipio"	TEXT,
	PRIMARY KEY("id" AUTOINCREMENT)
);

